INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'jacksonville'), 'RR-Acre', 'rr-acre', 'Residential Rural-Acre District', 'This district provides rural estate residential opportunities, primarily for single-family dwellings and mobile homes on large lots in suburban and rural areas of the City.', 35, NULL, 43560, 25, 25, 10, 10, 'Two spaces per single-family dwelling.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 'rr-acre' AND z.city_id = (SELECT id FROM cities WHERE slug = 'jacksonville') AND pu.name IN ('Single-family dwellings', 'Mobile homes', 'Foster care homes', 'Community residential homes (6 or fewer residents)', 'Family day care homes', 'Essential services (water, sewer, gas, telephone, radio, television, electric)', 'Churches', 'Golf courses', 'Neighborhood parks, pocket parks, playgrounds, recreational structures', 'Country clubs', 'Animals (other than household pets)', 'Home occupations') ON CONFLICT DO NOTHING;
INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'jacksonville'), 'RLD-60', 'rld-60', 'Residential Low Density-60 District', 'This district is designed for low-density residential living, primarily allowing single-family homes to promote a spacious neighborhood environment.', 35, NULL, 6000, 50, 20, 10, 5, 'Two spaces per single-family dwelling.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 'rld-60' AND z.city_id = (SELECT id FROM cities WHERE slug = 'jacksonville') AND pu.name IN ('Single-family dwellings', 'Cemeteries and mausoleums (by exception, no funeral homes)', 'Schools (meeting specific standards)', 'Parks', 'Accessory uses (detached garages, sheds)', 'Foster care homes', 'Family day care homes', 'Community residential homes (6 or fewer residents)') ON CONFLICT DO NOTHING;
INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'jacksonville'), 'RHD-A', 'rhd-a', 'Residential High Density-A District', 'This district supports higher density housing like apartments and condominiums, fitting urban areas needing diverse housing options.', 45, NULL, NULL, NULL, 25, 40, 40, 'Two spaces per townhome or condominium unit, plus one guest space per three units.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 'rhd-a' AND z.city_id = (SELECT id FROM cities WHERE slug = 'jacksonville') AND pu.name IN ('Multi-family dwellings (apartments, condominiums)') ON CONFLICT DO NOTHING;
INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'jacksonville'), 'CO', 'co', 'Commercial Office District', 'This district focuses on office buildings and professional services, often serving as a transition between residential and more intensive commercial areas.', 60, NULL, 7500, 50, 10, 10, 0, 'Three spaces per 1,000 square feet of gross floor area for professional and business offices (maximum six spaces per 1,000 sqft). Child or adult care centers limited to 150 children/adults.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 'co' AND z.city_id = (SELECT id FROM cities WHERE slug = 'jacksonville') AND pu.name IN ('Medical and dental or chiropractor offices and clinics (not hospitals)', 'Professional and business offices', 'Multi-family residential (vertically integrated with ground floor permitted use)', 'Neighborhood retail sales and service establishments (individual building footprint <= 40,000 sqft)', 'Service establishments (barber/beauty shops, shoe repair)', 'Restaurants (without drive-in/drive-through)', 'Banks (without drive-thru tellers) and financial institutions, travel agencies', 'Libraries, museums, community centers', 'Automated Car Washes/Auto Laundry (meeting performance standards)') ON CONFLICT DO NOTHING;
INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'jacksonville'), 'CN', 'cn', 'Commercial Neighborhood District', 'This district permits retail uses, office commercial uses, and service establishments that serve the daily needs of contiguous residential neighborhoods.', 60, NULL, 7500, 50, 10, 10, 0, 'One space per 250 square feet of retail space. Child or adult care centers limited to 150 children/adults.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
