INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'jacksonville'), 'CRO', 'cro', 'Commercial, Residential and Office District', 'This district permits a mix of medical and professional offices, multiple-family dwellings, and limited retail/service establishments, often serving as a transition area.', 45, NULL, 7000, 50, 20, 20, 10, 'Three spaces per 1,000 square feet of gross floor area for professional and business offices (maximum six spaces per 1,000 sqft). Two spaces per multiple-family dwelling unit, plus one guest space per three units. Child or adult care centers limited to 150 children/adults.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 'cro' AND z.city_id = (SELECT id FROM cities WHERE slug = 'jacksonville') AND pu.name IN ('Medical and dental office or clinics (not hospitals)', 'Professional and business offices', 'Multiple-family dwellings', 'Single-family dwellings (pre-Comprehensive Plan)', 'Schools, vocational/trade/business schools, colleges and universities', 'Fraternity and sorority houses', 'Churches', 'Parks, playgrounds, playfields, recreational/community structures', 'Adult Congregate Living Facility', 'Libraries, museums, community centers', 'Radio and television broadcasting studios and offices', 'Banks (without drive-through), savings and loan institutions', 'Art galleries, dance, art, gymnastics, fitness centers, martial arts, music studios, theaters for stage performances (not motion picture theaters)', 'Cosmetology and similar uses', 'Bed and breakfast establishments', 'Restaurants (on-premises alcohol only, seating limits)', 'Community residential homes (up to 6 residents)', 'Hospice facilities', 'Employment office (not day labor pool)', 'Cottages') ON CONFLICT DO NOTHING;
INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'jacksonville'), 'CCG-1', 'ccg-1', 'Commercial Community/General-1 District', 'This district allows a wide range of retail sales and services, including general merchandise, apparel, food, and related items, as well as offices and highway commercial uses.', 60, NULL, NULL, NULL, NULL, 10, 0, 'One space per 300 square feet of gross floor area for most retail establishments.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 'ccg-1' AND z.city_id = (SELECT id FROM cities WHERE slug = 'jacksonville') AND pu.name IN ('Commercial retail sales and service establishments', 'Banks (including drive-thru tellers), loan companies, mortgage brokers, stockbrokers', 'All types of professional and business offices', 'Hotels and motels', 'Commercial indoor recreational or entertainment', 'Retail outlets for food, drugs, apparel, toys, books, jewelry, art, cameras, sporting goods, hobby shops, pet shops, musical instruments, florists, delicatessens, bakeries, home furnishings, office equipment, antiques, hardware, new automobile parts', 'Service establishments (barber/beauty shops, shoe repair, restaurants, interior decorators, reducing salons/gymnasiums, self-service laundries/dry cleaners, tailors/dressmakers, laundries/dry cleaning pickup stations, dry cleaning/laundry package plants, radio/television broadcasting offices/studios, communication antennas/towers, funeral homes, marinas, blueprinting, job printing, radio/television repair shops, travel agencies, employment offices, home equipment rental)', 'Establishments with retail sale and service of alcoholic beverages (on-premises or off-premises)', 'Bottle clubs', 'Residential treatment facilities and emergency shelters', 'Crematories', 'Service stations, service garages for minor repairs, car washes') ON CONFLICT DO NOTHING;
INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'jacksonville'), 'CCBD', 'ccbd', 'Commercial Central Business District', 'This is a high-density mixed-use area intended to promote revitalization and growth in downtown, ensuring compatibility between new and existing uses, and promoting access to the St. Johns River. It is the single zoning district for almost all Downtown properties (excluding PUDs).', NULL, NULL, NULL, 95, NULL, NULL, NULL, 'No off-street parking required for dwelling units in existing nonresidential structures; one space per dwelling unit for new construction. For other uses, three spaces per 1,000 square feet of gross floor area (maximum six spaces per 1,000 sqft).') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 'ccbd' AND z.city_id = (SELECT id FROM cities WHERE slug = 'jacksonville') AND pu.name IN ('Marinas', 'Parks', 'Hotel', 'Commercial office', 'Specialty retail', 'High-rise residential development', 'Mixed-use developments', 'Outdoor commercial or recreational activity (with permit)', 'Personal property storage establishments', 'Commercial Surface Parking Lot', 'Filling or Fueling Stations (fewer than 8 fueling stations)', 'Service garage for minor repairs (no outdoor storage, bays not facing public right-of-way)', 'Auto laundry', 'Thrift stores (retail outlets for used goods)', 'Day Labor pool (activities within enclosed facility)', 'Permanent or restricted outside sale and service of food and beverages (including alcohol)') ON CONFLICT DO NOTHING;
INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'jacksonville'), 'IL', 'il', 'Industrial Light District', 'This district permits light industrial uses, offices, public facilities, and supporting retail commercial uses with fewer objectionable impacts such as noise, odor, toxic chemicals, and wastes.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'One space per 2,000 square feet of gross floor area for industrial, wholesale, warehouse, storage, and similar uses.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 'il' AND z.city_id = (SELECT id FROM cities WHERE slug = 'jacksonville') AND pu.name IN ('Wholesaling, warehousing, storage or distribution establishments', 'Light manufacturing, processing (including food processing but not slaughterhouse), packaging or fabricating', 'Printing, publishing or similar establishments', 'Business and professional offices', 'Service establishments catering to commerce and industry', 'Light assembly and manufacturing', 'Manufacturing of paints, enamels and allied products', 'Concrete batching plants', 'Research and development activities', 'Transportation terminals (including freight terminals)', 'Radio/T.V. studios, transmission and relay towers', 'Yard waste composting, recycling facilities', 'Medical clinics, veterinary offices', 'Vocational/trade schools and building trade contractors', 'Railroad yards, truck terminals, bus and rail stations', 'Solid waste management facilities', 'Institutional uses and public facilities', 'Utility plants and facilities') ON CONFLICT DO NOTHING;
INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'jacksonville'), 'IH', 'ih', 'Industrial Heavy District', 'This district generally involves creating or utilizing materials or products predominantly from extracted or raw materials, or activities that potentially involve hazardous or commonly recognized offensive conditions. It is the most likely to produce adverse physical and environmental impacts.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'One space per 2,000 square feet of gross floor area for industrial, wholesale, warehouse, storage, and similar uses.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 'ih' AND z.city_id = (SELECT id FROM cities WHERE slug = 'jacksonville') AND pu.name IN ('Research and development activities', 'Transmission and relay towers', 'Mining', 'Heavy manufacturing, repair, fabrication, assembly, packaging, processing, distribution', 'Transportation operations, railroad switching yards', 'Solid waste management facilities (including composting and recycling operations)', 'Utility plants', 'Manufacturing, processing, storage or transportation of paper and pulp, scrap metal, explosives, paint, oil, turpentine, shellac, lacquer or varnish and similar other hazardous and toxic materials', 'Petroleum refining (including components and raw materials)', 'Uses engaged in the basic processing and manufacturing of materials or products predominantly from extracted or raw materials', 'Storage of, or manufacturing processes using flammable or explosive materials', 'Storage or manufacturing processes that potentially involve hazardous conditions', 'Operation, parking, and maintenance of vehicles, cleaning of equipment or work processes involving solvents, solid waste or sanitary waste transfer stations, recycling establishments, truck terminals, public works yards, and container storage', 'All public facilities and non-residential uses permitted in residential and commercial land use categories (except public schools)') ON CONFLICT DO NOTHING;
